mapper.select:
SELECT c.*, ste.site_nm AS site_nm, vnd.vendor_nm AS vendor_nm, cat.category_nm AS category_nm, cd_sc.code_label AS settle_cycle_cd_nm FROM st_settle_config c LEFT JOIN sy_site ste ON ste.site_id = c.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = c.vendor_id LEFT JOIN pd_category cat ON cat.category_id = c.category_id LEFT JOIN sy_code cd_sc ON cd_sc.code_grp = 'SETTLE_CYCLE' AND cd_sc.code_value = c.settle_cycle_cd
ORDER BY c.settle_config_id ASC ORDER BY c.settle_config_id DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT c.*, ste.site_nm AS site_nm, vnd.vendor_nm AS vendor_nm, cat.category_nm AS category_nm, cd_sc.code_label AS settle_cycle_cd_nm FROM st_settle_config c LEFT JOIN sy_site ste ON ste.site_id = c.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = c.vendor_id LEFT JOIN pd_category cat ON cat.category_id = c.category_id LEFT JOIN sy_code cd_sc ON cd_sc.code_grp = 'SETTLE_CYCLE' AND cd_sc.code_value = c.settle_cycle_cd
ORDER BY c.settle_config_id ASC ORDER BY c.settle_config_id DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

mapper.update:
UPDATE st_settle_config
site_id = #{siteId}, vendor_id = #{vendorId}, category_id = #{categoryId}, settle_cycle_cd = #{settleCycleCd}, settle_day = #{settleDay}, commission_rate = #{commissionRate}, min_settle_amt = #{minSettleAmt}, settle_config_remark = #{settleConfigRemark}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE settle_config_id = #{settleConfigId}
